
export enum RequestType {
    POST,
    GET
}

export const ErrorStatus = {
    ABORTED: "ABORTED",
    NETWORK_ERROR: "NETWORK_ERROR",
    DATA_ERROR: "DATA_ERROR"
};

export class WebCommunication {
    public static get ErrorStatus() {
        return ErrorStatus;
    }

    public static readonly RequestType = RequestType;

    public static sendMessage(requestType:RequestType, path:string, data: any, dataVerification:(response:any, status:number)=>boolean, cb:(err:Error, response:any, status:number)=>void): XMLHttpRequest {
        // get a string representation of the request type
        let requestTypeString = this.RequestType[requestType];
        let requestPath = path;
        let request:XMLHttpRequest = new XMLHttpRequest();
        request.open(requestTypeString, requestPath, true);
        request.setRequestHeader('Content-Type', 'application/json');
        // request is complete
        request.onload = () => {
            let response:any = null;
            try {
                response = request.response? JSON.parse(request.response) : request.response;

                if(!dataVerification(response, request.status)) {
                    let error = new Error(`Client expected different response from server: ${request.response}`);
                    error.name = ErrorStatus.DATA_ERROR;
                    cb(error, null, request.status);
                    return;
                }
            } catch(ex) {
                let error = new Error(`Server sent back invalid json: ${request.response}, exception: ${ex}`);
                error.name = ErrorStatus.DATA_ERROR;
                cb(error, null, request.status);
                return;
            }
            cb(null, response, request.status);
        };
        request.onabort = ()=>{
            let error = new Error(`request aborted for path: ${requestPath} with data: ${JSON.stringify(data)}`);
            error.name = ErrorStatus.ABORTED;
            cb(error, null, request.status);
        };
        request.onerror = ()=>{
            let error = new Error(`request failed for path: ${requestPath} with data: ${JSON.stringify(data)}`);
            error.name = ErrorStatus.NETWORK_ERROR;
            cb(error, null, request.status);
        };
        request.send(JSON.stringify(data));
        return request;
    }
}

export default WebCommunication;
