import { AmbientSpike } from 'jibo-cai-utils';
import { system } from '../SystemService';
import { TunableDebug } from './utils/TunableDebug';
import { Log } from 'jibo-log';

/**
 * Detect spikes in the input energy stream.
 * Typical values range from -60dB to ~10dB depending on noise level. 0dB is the loudest sound the speaker can detect.
 */
export class AmbientAudioSpike extends AmbientSpike {

	constructor() {
		super( 'AmbientAudioSpike', {
			statOptions: {
				baselineSize: 2400,
				recentSize: 20,
				minimumRecentMean: -55,
				minimumBaselineStdDev: 2.7,
				divergenceSensitivity: 1.9,
			},
			spikeTimeoutMs: 500,
			alwaysEmitAbove: -30,
		});
	}

	init(parentLog: Log) {
		TunableDebug.setup(this);
		system.events.inputEnergy.on((data) =>	this.addSample(data.db_rms));
	}
}