import {Analytics, Jetstream, Versions, GlobalEvents} from './Types';

export interface ServiceContainer {
    analytics?: Analytics;
    jetstream?: Jetstream;
    versions?: Versions;
    globalEvents?: GlobalEvents;
}

//staticly implements ServiceContainer to supply the variables to all service clients
//so that they don't have to save a local variable themselves
export class ServiceOwner {
    private static _owner:ServiceContainer;

    public static init(owner:ServiceContainer) {
        this._owner = owner;
    }

    public static get analytics() {
        return this._owner.analytics;
    }

    public static get jetstream() {
        return this._owner.jetstream;
    }

    public static get versions() {
        return this._owner.versions;
    }

    public static get globalEvents() {
        return this._owner.globalEvents;
    }
}
