import {Log} from 'jibo-log';
import {WebCommunication} from '../utils/WebCommunication';
import {ServiceRecord, InitCallback, Callback} from '../utils/Types';

/**
 * @namespace jibo.secureTransferService
 * @intdocs
 */
let _httpInterface:string;
let _wsInterface:string;
let _initialized:boolean;

/**
 * Initialize the error service module for `jibo.init`.
 * @method jibo.secureTransferService#init
 * @param service {Object} The service options
 * @param service.host {String} host name
 * @param service.port {String} port number
 * @param callback {Function} callback
 */
export function init(service:ServiceRecord, parentLog:Log, callback:InitCallback):void {
    _httpInterface = "http://" + service.host + ":" + service.port;
    _wsInterface = "ws:" + service.host + ":" + service.port;
    _initialized = true;
    callback();
}

/**
 * A method to know whether or not we have backup data
 * @method jibo.secureTransferService#hasBackupData
 * @param callback {Function} callback - passes a bool via the callback params which signals if we have backup data
 */
export function hasBackupData(callback:Callback<boolean>):void {
    WebCommunication.sendMessage(WebCommunication.RequestType.GET, _httpInterface + '/hasBackupData', {},
    (response:any, status:number)=>{
        return (response.hasOwnProperty('isReady') && status === 200);
    },
    (err, response)=>{
        if(err) {
            callback(err, null);
        } else {
            callback(null, Boolean(response.isReady));
        }
    });
}

/**
 * Poll this method to know (via callback) if the UGC Key is ready in the SecureTransferService
 * @method jibo.secureTransferService#isUGCKeyReady
 * @param callback {Function} callback - passes a bool via the callback params which signals if the UGC key is ready
 */
export function isUGCKeyReady(callback:Callback<boolean>):void {
    WebCommunication.sendMessage(WebCommunication.RequestType.GET, _httpInterface + '/UGCKeyReady', {},
    (response:any, status:number)=>{
        return (response.hasOwnProperty('isReady') && status === 200);
    },
    (err, response)=>{
        if(err) {
            callback(err, null);
        } else {
            callback(null, Boolean(response.isReady));
        }
    });
}
