import {Log} from 'jibo-log';
import {ServiceRecord, InitCallback, Callback} from '../utils/Types';

/**
 * Schedule a job to run on the robot in the background.
 * @namespace jibo.scheduler
 * @intdocs
 */

export type SkillData = {
    skill:string;
    domain:string;
    intent:string;
};


export interface OTARecord {
    id:string;
    subsystem:string;
    changes:string;
    length:number;
    toVersion:string;
    dependencies:any;
    downloaded:boolean;
}

let _httpInterface:string = null;
let _initialized:boolean = false;


/**
 * Initialize the performance module for `jibo.init`.
 * @method jibo.scheduler#init
 * @param service {Object} The service options
 * @param service.host {String} host name
 * @param service.port {String} port number
 * @param callback {Function} callback
 * @intdocs
 */
export function init(service:ServiceRecord, parentLog:Log, callback:InitCallback):void {
    _httpInterface = "http://" + service.host + ":" + service.port;
    _initialized = true;
    callback();
}


/**
 * Trigger an instant robot backup
 * @method jibo.scheduler#backupRobot
 * @param callback {Function} callback
 * @intdocs
 */
export function backupRobot(callback:Callback<void>):void {
    _sendRequest('/backup-robot', callback);
}

/**
 * Get the current state of a backup, if applicable
 * @method jibo.scheduler#backupStatus
 * @param callback {Function} callback
 * @intdocs
 */
export function backupStatus(callback:Callback<any>):void {
    if(!_initialized) {
        return callback(new Error('Scheduler Service not initialized.'));
    }

    let request:XMLHttpRequest = new XMLHttpRequest();
    request.open("POST", _httpInterface + '/backup-status', true);
    request.onreadystatechange = () => {

        // request is complete
        if(request.readyState === 4) {
            let response = null;
            try {
                response = JSON.parse(request.response);
            }
            catch(e) {
                return callback(new Error('Scheduler.backupRobot response is not JSON. Timed out or bad format? ' + e));
            }

            // "OK" status
            if(request.status === 200) {
                callback(null, response.data);
            }
            else {
                // failure if anything else
                callback(new Error(response.message));
            }
        }
    };
    request.send();
}

