/**
 * Add a job to the scheduler service.
 * @method jibo.scheduler#addJob
 * @param schedule {String} The schedule (crontab syntax).
 * @param data {Object} Options for the skill redirect request.
 * @param callback {Function} callback
 * @intdocs
 */
export function addJob(schedule:string, skillData:SkillData, callback:Callback<string>):void {
    if(!_initialized) {
        return callback(new Error('Scheduler Service not initialized.'));
    }

    let request:XMLHttpRequest = new XMLHttpRequest();
    request.open("POST", _httpInterface + '/add', true);
    request.onreadystatechange = () => {
        // request is complete
        if(request.readyState === 4) {
            let response = null;
            try {
                response = JSON.parse(request.response);
            }
            catch(e) {
                return callback(new Error('Scheduler.addJob response is not JSON. Timed out or bad format? ' + e));
            }

            // "OK" status
            if(request.status === 200) {
                callback(null, response.job);
            }
            else {
                // failure if anything else
                callback(new Error(response.message));
            }
        }
    };
    request.send(JSON.stringify({
        schedule,
        skillData
    }));
}

