function _sendRequest(url:string, callback:Callback<void>):void {
    if(!_initialized) {
        return callback(new Error('Scheduler Service not initialized.'));
    }

    let request:XMLHttpRequest = new XMLHttpRequest();
    request.open("POST", _httpInterface + url, true);
    request.onreadystatechange = () => {

        // request is complete
        if(request.readyState === 4) {
            let response = null;
            try {
                response = JSON.parse(request.response);
            }
            catch(e) {
                return callback(new Error('Scheduler ' + url + ' response is not JSON. Timed out or bad format? ' + e));
            }

            // "OK" status
            if(request.status === 200) {
                callback(null);
            }
            else {
                // failure if anything else
                callback(new Error(response.message));
            }
        }
    };
    request.send();
}
