import {Log} from 'jibo-log';
import {HTTPClient} from 'jibo-client-framework';
import {ServiceRecord, InitCallback, Callback} from '../utils/Types';
import {lps} from './LPSService';

/**
 * @description
 * Acts within lps service and so is not exposed by hanging off of jibo object.
 *
 * @namespace jibo.ics
 * @intdocs
 */
let httpUrl:string = null;
let http:HTTPClient = null;
let isInitialized:boolean = false;

export function init(service:ServiceRecord, parentLog:Log, cb:InitCallback) {
    if (!service.host || typeof service.host !== 'string') {
        throw new Error(`Missing required service.host`);
    }
    httpUrl = "http://" + service.host + ":" + service.port;
    isInitialized = true;

    http = new HTTPClient(service.host, service.port);
    cb();
}


/**
 * Create new entry in LPS identity list.
 * @param data {Object} Options for the request.
 * @param data.name {String} Name for the identity.
 * @param [data.kind="face"] {String} Kind of identity data. (Currently ONLY supports "face".)
 * @param cb {Function} Callback for the method.
 * @method jibo.ics#createIdentity
 * @intdocs
 */
export function createIdentity(data:{name:string, kind?:string}, cb:Function){
    _sendIdentityRequest('/identity/create', data, cb);
}

/**
 * Remove entry from LPS identity list.
 * @param data {Object} Options for the request.
 * @param data.name {String} Name for the identity.
 * @param [data.kind="face"] {String} Kind of identity data. (Currently ONLY supports "face".)
 * @param cb {Function} Callback for the method.
 * @method jibo.ics#removeIdentity
 * @intdocs
 */
export function removeIdentity(data:{name:string, kind?:string}, cb:Function){
    _sendIdentityRequest('/identity/remove', data, cb);
}

/**
 * Get list of all face-trained users
 * @method jibo.ics#getIdentityList
 * @param cb {Function} Callback for the method.
 * @intdocs
 */
export function getIdentityList(cb:Callback){
    let request = new XMLHttpRequest();
    request.open('GET', httpUrl + '/identity/list', true);
    request.onreadystatechange = () => {
        if (request.readyState === 4) {
            if (request.status >= 200 && request.status <= 299) {
                if (request.response) {
                    // success!
                    let response;
                    let error = null;
                    try {
                        response = JSON.parse(request.response);
                    }
                    catch (e) {
                        response = null;
                        error = e;
                    }

                    cb(error, response);
                }
                else {
                    cb('No data received from identity service', null);
                }
            }
            else {
                // failure if anything else
                let msg = 'Identity service unavailable';
                if(request.statusText !== undefined && request.statusText !== "") {
                    msg = request.statusText;
                }

                cb(msg, null);
            }
        }
    };
    request.send();
}

/**
 * Get face location details
 * @method jibo.ics#getFaceLocationDetails
 * @param looperId {String}
 * @param photoIndex {Number}
 * @param cb {Function} Callback for the method.
 * @return {Object} requested face location details
 * @intdocs
 */
export function getTrainingPhotoMetadata(looperId: string, photoIndex:number, cb:Callback) {
    let request = new XMLHttpRequest();
    request.open('GET', `${httpUrl}/identity/detection?name=${looperId}&kind=face&index=${photoIndex}`, true);
    request.onreadystatechange = () => {
        if (request.readyState === 4) {
            if (request.status >= 200 && request.status <= 299) {
                if (request.response) {
                    // success!
                    let response;
                    let error = null;
                    try {
                        response = JSON.parse(request.response);
                    }
                    catch (e) {
                        response = null;
                        error = e;
                    }
                    if (response.detection) {
                        cb(error, response.detection);
                    }
                    else {
                        cb('data received from identity service does not include detection property', response);
                    }

                }
                else {
                    cb('No data received from identity service', null);
                }
            }
            else {
                // failure if anything else
                let msg = 'Identity service unavailable';
                if(request.statusText !== undefined && request.statusText !== "") {
                    msg = request.statusText;
                }

                cb(msg, null);
            }
        }
    };
    request.send();
}

/**
 * Returns URI of face-training photo JPEG
 * @method jibo.ics#getTrainingPhoto
 * @param looperId {String} Name for the identity.
 * @param photoIndex {Number} Index of the photo to get
 * @return URI of face training photo JPEG
 * @intdocs
 */
export function getTrainingPhotoURI(looperId:string, photoIndex:number):string{
    const path = '/identity/photo';
    const queryString = `?name=${looperId}&index=${photoIndex}&kind=face`;
    return `${httpUrl}${path}${queryString}`;
}

export interface TrainingRequestResponse {
    detection?:any;
    detections?:any[];
}
/**
 * Set up new training request. Request LPS to train an identified for a name using current sensor data.
 * @method jibo.ics#sendTrainingRequest
 * @param data {Object} Options for the training request.
 * @param data.name {String} Name for the training data.
 * @param [data.kind="face"] {String} Kind of data to be trained on. (Currently ONLY supports "face".)
 * @param cb {Function} Callback for the method.
 * @intdocs
 */
export function sendTrainingRequest(data:{name:string, kind?:string}, cb:Callback<TrainingRequestResponse>){
    //note that this goes through the LPS system, not the regular identity service
    //according to the platform team, this is like a shorthand for:
    //  POST http://<media-service>/media/photo
    //  GET http://<media-service>/media/photo?id=<id>
    //  POST http://<identity-service>/identity/train FORM: jpeg photo
    const path = '/lps/identity/train';
    _sendIdentityRequest(path, data, cb, lps.httpUrl);
}

/**
 * Send identity requests.
 * @param path {String} HTTP path to specify identity request.
 * @param data {Object} Options for the request.
 * @param data.name {String} Name for the identity.
 * @param [data.kind="face"] {String} Kind of identity data. (Currently ONLY supports "face".)
 * @param cb {Function} Callback for the method.
 * @param [httpUrlOverride] {String} Override the httpUrl (IP and port of the service)
 * @method jibo.ics#_sendIdentityRequest
 * @private
 */
function _sendIdentityRequest(path:string, data:{name:string, kind?:string}, cb:Function, httpUrlOverride?:string) {
    if (httpUrl === undefined) {
        cb('Identity service is not initialized', null);
        return;
    }

    let params:any = {};

    // name is a required parameter - if not present, return immediately
    if (!data.hasOwnProperty('name')){
        cb("Identity data must have 'name' property", null);
        return;
    }

    // these are NOT required parameters - if not present, use defaults
    if (!data.hasOwnProperty('kind')){ data.kind = "face";}

    params.name = data.name;
    params.kind = data.kind;

    let request = new XMLHttpRequest();
    request.open("POST", (httpUrlOverride || httpUrl) + path, true);
    request.onreadystatechange = () => {
        if (request.readyState === 4) {
            if (request.status >= 200 && request.status < 300) {
                cb();
            }
            else {
                // failure if anything else
                let msg = 'Identity service unavailable';
                if(request.statusText !== undefined && request.statusText !== "") {
                    msg = request.statusText;
                }

                // console.log("lps " + path + " response");
                // console.log(request);

                let errorData = null;
                if (request.response) {
                    try {
                        errorData = JSON.parse(request.response);
                    }
                    catch (e) {
                        errorData = 'Response is not JSON.';
                    }
                }

                cb(msg, errorData);
            }
        }
    };
    request.send(JSON.stringify(params));
}
