import { AmbientAudioSpike } from "../AmbientAudioSpike";

let tunable = null;
try {
	tunable = require('jibo-tunable');
} catch (e) {
	// No tunable library found, disabling debug
}

const WIN_CIRC = 'Detectors';
export class TunableDebug {
	static setup (audioTrigger: AmbientAudioSpike) {
		if (tunable) {
			const T = tunable.Tunable;

			let baselineSize = 2400;
			T.getNumberField('Baseline audio length', baselineSize, 200, 4000, -1, WIN_CIRC).events.change.on(value => {
				baselineSize = Math.floor(value);
			});

			let recentSize = 20;
			T.getNumberField('Recent audio length', recentSize, 5, 200, -1, WIN_CIRC).events.change.on(value => {
				recentSize = Math.floor(value);
			});

			T.getButtonField(`Change buffer lengths`, WIN_CIRC).events.change.on(() => {
				audioTrigger.resetSize(baselineSize, recentSize);
			});

			T.getNumberField('Set ambient noise threshold', 2.2, 0, 5, -1, WIN_CIRC).events.change.on(value => {
				audioTrigger.setDivergenceSensitivity(value);
			});
		}
	}
}