import IdentityInterface from "./IdentityServiceInterface";
import { IdentityEvents } from './IDEvents';
import {DataConverter} from "./DataConverter";
import {lps} from "../LPSService";
import {ServiceOwner} from '../../utils/ServiceOwner';
import {LPSEntity, SpeakerRecord, PresenceRecord, Person, SensoryType} from "jibo-common-types";
import {Log} from 'jibo-log';
import { types as JetstreamTypes } from '@jibo/jetstream-client';

//import parentLog from '../../log';
//const log = parentLog.createChild("ID");
let log:Log;

// https://confluence.jibo.com/display/ENG/LPS+Service
// THIS IS IMPORTANT.

/**
 * @description
 * Identity Module.
 * Get identity information from Jibo's LPS. including
 * present persons, present speaker, person location, as well as
 * detailed information about speaker and face ID.
 *
 * ```
 * var jibo = require("jibo");
 * jibo.lps.identity.getPresentPersons();
 * ```
 * @namespace jibo.lps.identity
 */
class Identity implements IdentityInterface {
    /**
     * Identity Events
     * @name jibo.lps.identity#events
     * @type {jibo.lps.identity.IdentityEvents}
     */
    public events: IdentityEvents = new IdentityEvents();

    /**
     * Data converter helper to accept and convert LPS data
     * @name jibo.lps.identity#dataConverter
     * @type {jibo.lps.identity.DataConverter}
     * @private
     */
    private dataConverter: DataConverter;

    /**
     * Keep interval handler for unregistering when dispose is called
     * @name jibo.lps.identity~intervalHandle
     * @type {any}
     * @private
     */
    private intervalHandle: any = null;

    /**
     * Keep wake handler for unregistering when dispose is called
     * @name jibo.lps.identity~wakeHandlerFunction
     * @type {any}
     * @private
     */
    private wakeHandlerFunction: any = null;


    /**
     * LPS Instance for piping identity-specific calls.
     * @name jibo.lps.identity~lps
     * @type {LPSService}
     * @private
     */
    private lps: typeof lps;

    /**
     * @param {LPSService} lps service instance
     * @constructor
     */
    constructor(lpsService: typeof lps) {
        this.lps = lpsService;
        this.dataConverter = new DataConverter(this.events);
    }

    /**
     * @description Begins the polling of LPS websocket on timescale. Sends
     * data to DataConverter to be handled.
     * @method jibo.lps.identity#init
     */
    public init(parentLog:Log) {
        if (this.intervalHandle !== null || this.wakeHandlerFunction !== null) {
            log.warn("IDEvents being initted, but it is already initted!");
            return;
        }
        log = parentLog.createChild("ID");
        this.dataConverter.init(parentLog.createChild('Identity'));

        this.lps.events.motion.on(data => this.dataConverter.acceptAwareness(data));
        this.lps.events.audio.on(data => this.dataConverter.acceptAudio(data));

        if (!ServiceOwner.jetstream) {
            //not an error in the SSM
            log.info('IDEvents initted without jetstream');
        } else {
            ServiceOwner.jetstream.events.speakerID.on(data => this.setActiveSpeaker(data, 'JETSTREAM'));
        }
    }

    /**
     * @description Returns `true` if one or more persons are present in the robot's environment.
     * @returns {boolean} `true` if someone is present.
     * @method jibo.lps.identity#isAnyonePresent
     */
    public isAnyonePresent(): boolean {
        log.debug("isAnyonePresent? ", this.dataConverter.people.size > 0);
        return this.dataConverter.people.size > 0;
    }

    /**
     * @description Returns `true` if one or more persons are in the robot's field of view.
     * @returns {boolean} `true` if someone is visible.
     * @method jibo.lps.identity#isAnyoneVisible
     */
    public isAnyoneVisible(): boolean {
        const visible = this.dataConverter.visibleFaces.size > 0;
        log.debug("isAnyoneVisible? ", visible);
        return visible;
    }

    /**
     * @description Returns a list of persons who are present in the robot's environment.
     * Persons may be identified (known/in-loop) or unidentified.
     * @returns {Array<jibo.lps.identity#Person>} List of present persons.
     * @method jibo.lps.identity#getPresentPersons
     */
    public getPresentPersons(): Person[] {
        let people: Person[] = [];
        this.dataConverter.people.forEach((person:LPSEntity) => {
            people.push({
                id: person.id_summary.name,
                entityId: person.id,
                type: person.id_summary.kind,
                confidence: person.confidence
            });
        });
        return people;
    }

    /**
     * @description Returns a list of persons who are in the robots field of view
     * Persons may be identified (known/in-loop) or unidentified.
     * @returns {Array<jibo.lps.identity#Person>} List of visible persons.
     * @method jibo.lps.identity#getVisiblePersons
     */
    public getVisiblePersons(): Person[] {
        let people: Person[] = [];
        for (let entity of this.dataConverter.visibleFaces.values()) {
            people.push({
                id: entity.id_summary.name,
                entityId: entity.id,
                type: entity.id_summary.kind,
                confidence: entity.confidence
            });
        }
        return people;
    }

    /**
     * @description Call this method to provide top-down ("ground truth") notification that a particular person is present
     * in the robot's environment.
     * @param {string} id - Unique ID of the person who is present.
     * @param {Function} [callback] Callback for information about LPS call request status.
     * @method jibo.lps.identity#setPresentPerson
     */
    public setPresentPerson(id: string, callback: ()=>void): void {
        const presenceData = new PresenceRecord({
            'name': id,
            'kind': SensoryType.PERSON, // this is the deprecated type of the `kind` field used here until platform is updated to handle the new kind
            'present': true,
            'confidence': 1
        });
        this.lps.setPresence(presenceData, callback);
    }

    /**
     * @description Returns the most recent speaker out of the persons who are present in the robot's environment,
     * or null if no such person is present.
     * @param {number} [age=30000] Acceptable age in ms of the most recent speaker event. Defaults 30 seconds.
     * @returns {jibo.lps.identity#Person} Person who is speaking.
     * @method jibo.lps.identity#getActiveSpeaker
     */
    public getActiveSpeaker(age:number = 30000): SpeakerRecord {
        const mostRecent = this.dataConverter.mostRecentSpeaker(age);
        log.debug("most recent speaker", mostRecent);
        if (mostRecent) {
            if (mostRecent.idInfo) {
                log.debug("getActiveSpeaker. entity: ", mostRecent.entity, "id: ", mostRecent.idInfo.id, "is high confidence: ", mostRecent.idInfo.highConfidence);
            } else {
                log.debug("getActiveSpeaker. entity: ", mostRecent.entity);
            }
        } else {
            log.debug("getActiveSpeaker. None.");
        }

        return mostRecent;
    }

    /**
     * @description Sets the current speakerID
     * @param {jibo.jetstream.types.SpeakerIDData} data Raw speaker ID data
     * @param {'JETSTREAM' | 'JCP'} [source='JETSTREAM'] The source of the speaker ID
     * @method jibo.lps.identity#setActiveSpeaker
     */
    public setActiveSpeaker(data: JetstreamTypes.SpeakerIDData, source: 'JETSTREAM' | 'JCP' = 'JETSTREAM') {
        this.dataConverter.acceptSpeakerId(data, source);
    }

    /**
     * @description Gets the faces currently in jibo's FOV.
     * @returns {Map} Faces presently in Jibo's FOV as map of string ==> jibo.lps#LPSEntity
     * @method jibo.lps.identity#getVisibleFaces
     */
    public getVisibleFaces(): Map<string, LPSEntity> {
        return this.dataConverter.visibleFaces;
    }
}

export default Identity;
