import { AmbientAudioSpike } from "./AmbientAudioSpike";
import {Log} from 'jibo-log';

class Detector {
    /**
     * Look for a spike in an audio signal and emit an event
     */
    public ambientAudioSpike: AmbientAudioSpike;

    /**
     * @constructor
     */
    constructor() {
        this.ambientAudioSpike = new AmbientAudioSpike();
    }

    init(parentLog: Log) {
        this.ambientAudioSpike.init(parentLog);
    }

}

export default Detector;
