import * as async from 'async';
import { WSClient } from 'jibo-client-framework';
import { Event, EventContainer } from 'jibo-typed-events';
import { BodyState, TouchState, PowerSource, InputEnergy, AxisState, IMUState } from 'jibo-common-types';
import { TouchHandler } from './TouchHandler';
import { ServiceRecord, InitCallback, Callback } from '../utils/Types';
import {Log} from 'jibo-log';

let log: Log;

let bodyOutput: any;
/**
 * Body state of Jibo
 * @name jibo.system#bs
 * @type {TypedEvent}
 * @private
 */
let bs: BodyState = new BodyState();
/**
 * http interface url to the body service
 * @name jibo.system#bodyHttpInterface
 * @type {string}
 * @private
 */
let bodyHttpInterface: string;
/**
 * http interface url to the audio service
 * @name jibo.system#audioHttpInterface
 * @type {string}
 * @private
 */
let audioHttpInterface: string;
/**
 * WS url for body service
 * @name jibo.system#socketUrl
 * @type {string}
 * @private
 */
let socketUrl: string;
/**
 * The type of power source we're currently using.
 * @name jibo.system#powerSource
 * @type {jibo.system#PowerSource}
 * @private
 */
let powerSource: PowerSource;
/**
 * The state of Jibo's hatch
 * @name jibo.system#hatchOpen
 * @type {boolean}
 * @private
 */
let hatchOpen: boolean = false;
/**
 * Whether anything is externally moving jibo.
 * @name jibo.system#isMoving
 * @type {boolean}
 * @private
 */
let isMoving: boolean = false;
/**
 * Input Energy sensed by body system.
 * @name jibo.system~_inputEnergy
 * @type {jibo.system#InputEnergy}
 * @private
 */
let _inputEnergy: InputEnergy;
/**
 * Input Energy sensed by body system.
 * @name jibo.system~miscSocket
 * @type {jibo.system#InputEnergy}
 * @private
 */
let miscSocket: WSClient;
/**
 * Input Energy sensed by body system.
 * @name jibo.system~touchSocket
 * @type {jibo.system#InputEnergy}
 * @private
 */
let touchSocket: WSClient;
/**
 * Input Energy sensed by body system.
 * @name jibo.system~powerSocket
 * @type {jibo.system#InputEnergy}
 * @private
 */
let powerSocket: WSClient;
/**
 * socket to get incoming information about motor axis
 * @name jibo.system~axisSocket
 * @type {WSclient}
 * @private
 */
let axisSocket: WSClient;
/**
 * socket to get incoming information about Jibo's IMU State
 * @name jibo.system~imuSocket
 * @type {WSclient}
 * @private
 */
let imuSocket: WSClient;
/**
 * Handler for head touch state and events
 * @name jibo.system~touchHandler
 * @type {jibo.system#TouchHandler}
 * @private
 */
let touchHandler: TouchHandler;

/**
 * @description
 * Non-motion-related robot body services (i.e. temperature, fan, battery, backlight, etc.).
 *
 * ```
 * var jibo = require("jibo");
 * jibo.system.getBatteryTemperature();
 * ```
 * @namespace jibo.system
 */
export class system {
    /**
     * Set the body output.
     * @name jibo.system#output
     * @type {Object}
     * @intdocs
     */
    public static set output(_output) {
        bodyOutput = _output;
    }

    /**
     * `true` if the robot is plugged in.
     * @name jibo.system#pluggedIn
     * @type {boolean}
     */
    public static get pluggedIn() {
        return (bs.powerState.source === 'EXTERNAL');
    }

    /**
     * `true` if the robot's battery is charging.
     * @name jibo.system#batteryCharging
     * @type {boolean}
     */
    // The units are mA and full charging is 2000mA. As Martin said charging at 0.02 (20mA) is impossible.
    public static get batteryCharging() {
        return (bs.powerState.battery.charge_rate >= 0.1);
    }

    /**
     * Get the robot's charging rate.
     * @name jibo.system#batteryChargeRate
     * @type {number}
     */
    public static get batteryChargeRate() {
        return bs.powerState.battery.charge_rate;
    }

    /**
     * Get the robot's current touch pad state.
     * There is an array of 6 pads with `true` for touched and `false` for not touched.
     * See {@tutorial robot-info-tool} for a diagram of Jibo's head touch pads.
     * Three run vertically down the left side of Jibo's head from top to bottom: `pad_state[0, 1, 2]`.
     * Three run vertically down the right of his head: `pad_state[3, 4, 5]`.
     * @name jibo.system#padState
     * @type {boolean[]}
     */
    public static get padState() {
        return touchHandler.touchState.pad_state;
    }

    /**
     * Energy statistics for input audio at 20Hz.
     * @name jibo.system#inputEnergy
     * @intdocs
     */
    public static get inputEnergy() {
        return _inputEnergy;
    }
}

export namespace system {
    /**
     * @description
     * System events that are emitted upon data received.
     *
     * Example:
     * ```
     * jibo.system.events.touchChanged.on((data) => {
     *   console.log(data);
     * });
     * ```
     * @class SystemEvents
     * @memberof jibo.system
     */
    export class SystemEvents extends EventContainer {
        /**
         * Event for when the touch pad has changed states
         * @name jibo.system.SystemEvents#touchChanged
         * @type {TypedEvent}
         * @readOnly
         */
        public touchChanged: Event<TouchState>;
        /**
         * Emitted audio input energy changes.
         * @name jibo.system.SystemEvents#inputEnergy
         * @type {TypedEvent}
         * @readOnly
         */
        public inputEnergy: Event<InputEnergy>;
        /**
         * A touch pad has been turned on, where previously all were off.
         * WARNING: this refers to the local `touchOn` event, which is
         * NOT used to stop Jibo. If you want to listen for the
         * `touchStop` event AND clobber the stop behavior, please
         * refer to {@link jibo.globalEvents#touchStop}.
         * Emits array of pad state.
         * @name jibo.system.SystemEvents#touchOn
         * @type {TypedEvent}
         * @readOnly
         */
        public touchOn: Event<boolean[]>;
        /**
         * All touch pads are off, where previously at least one was on.
         * Emits array of pad state.
         * @name jibo.system.SystemEvents#touchOff
         * @type {TypedEvent}
         * @readOnly
         */
        public touchOff: Event<boolean[]>;
        /**
         * Axis fault on. Emits name of axis that faulted.
         * @name jibo.system.SystemEvents#axisFaultOn
         * @type {TypedEvent}
         * @readonly
         */
        public axisFaultOn: Event<AxisState>;
        /**
         * Axis fault has stopped. Emits that axis are all not faulting.
         * @name jibo.system.SystemEvents#axisFaultOff
         * @type {TypedEvent}
         * @readonly
         */
        public axisFaultOff: Event<AxisState>;
        /**
         * Jibo's hatch has opened
         * @name jibo.system.SystemEvents#hatchOpen
         * @type {TypedEvent}
         * @readonly
         */
        public hatchOpen: Event<void>;
        /**
         * Jibo's hatch has closed
         * @name jibo.system.SystemEvents#hatchClose
         * @type {TypedEvent}
         * @readonly
         */
        public hatchClose: Event<void>;
        /**
         * Jibo was just plugged in
         * @name jibo.system.SystemEvents#pluggedIn
         * @type {TypedEvent}
         * @readonly
         */
        public pluggedIn: Event<void>;
        /**
         * Jibo was just unplugged
         * @name jibo.system.SystemEvents#unplugged
         * @type {TypedEvent}
         * @readonly
         */
        public unplugged: Event<void>;
        // TODO implement these once platform has a better measure of this.
        /*
         * Jibo was picked up
         * @name jibo.system.SystemEvents#pickUp
         * @type {TypedEvent}
         * @readonly
         * @private
         */
        // public pickUp:Event<any>;
        /*
         * Jibo was put down
         * @name jibo.system.SystemEvents#putDown
         * @type {TypedEvent}
         * @readonly
         * @private
         */
        // public putDown:Event<any>;

        constructor() {
            super();
            this.touchChanged = new Event<TouchState>('System Touch Change Event');
            this.inputEnergy = new Event<InputEnergy>('Audio Input Energy changes');
            this.touchOn = new Event<boolean[]>('A Touch Pad Has Been Touched From None');
            this.touchOff = new Event<boolean[]>('All Touch Pads Turned Off');
            this.axisFaultOn = new Event<AxisState>('Motor Axis Fault On');
            this.axisFaultOff = new Event<AxisState>('Motor Axis Fault Off');
            this.hatchOpen = new Event<any>("Jibo's hatch was opened");
            this.hatchClose = new Event<any>("Jibo's hatch was closed");
            this.pluggedIn = new Event<any>('Jibo was plugged in');
            this.unplugged = new Event<any>('Jibo was unplugged');
            // TODO implement these
            // this.pickUp = new Event<any>('Jibo was picked up');
            // this.putDown = new Event<any>('Jibo was put down');
        }
    }

    /**
     * System Events
     * @name jibo.system#events
     * @type {jibo.system.SystemEvents}
     */
    export const events: SystemEvents = new SystemEvents();

    /**
     * Initialize the body service
     * @intdocs
     * @method jibo.system#initBody
     */
    export function initBody(service: ServiceRecord, parentLog: Log, callback: InitCallback) {
        log = parentLog.createChild("SystemService");
        touchHandler = new TouchHandler(events, parentLog);

        bodyHttpInterface = "http://" + service.host + ":" + service.port;
        socketUrl = "ws:" + service.host + ":" + service.port;

        async.parallel(
            [
                _createMiscSocket,
                _createTouchSocket,
                _createPowerSocket,
                _createAxisSocket,
                _createIMUSocket
            ],
            callback
        );
    }



    /**
     * Get the robot's battery temperature.
     * @method  jibo.system#getBatteryTemperature
     * @return {number} The temperature of the battery in degrees Celsius.
     */
    export function getBatteryTemperature() {
        return bs.powerState.battery.temp;
    }

    /** Get the robot's battery level.
     * @method jibo.system#getBatteryLevel
     * @return {number} The current level of the battery as a percentage.
     */
    export function getBatteryLevel() {
        return (bs.powerState.battery.capacity / bs.powerState.battery.max_capacity) * 100;
    }

    /**
     * Get the robot's system voltage.
     * @method jibo.system#getSystemVoltage
     * @return {number} The current system voltage estimate.
     */
    export function getSystemVoltage() {
        return bs.powerState.vsys;
    }

    /**
     * Get the robot's main board temperature.
     * @method jibo.system#getMainBoardTemperature
     * @return {number} The temperature of the main board in degrees Celsius.
     */
    export function getMainBoardTemperature() {
        return bs.miscState.main_board_temp;
    }

    /**
     * Get the robot's CPU temperature.
     * @method jibo.system#getCPUTemperature
     * @return {number} The temperature of the CPU in degrees Celsius.
     */
    export function getCPUTemperature() {
        return bs.miscState.cpu_temp;
    }

    /**
     * Get the touch state of pads in Jibo's head.
     * @method jibo.system#getTouchState
     * @returns {jibo.system.TouchState} The state of Jibo's head touchpads.
     */
    export function getTouchState() {
        return touchHandler.touchState;
    }

    /**
     * Get the robot's fan speed.
     * @method jibo.system#getFanSpeed
     * @param {Function} callback Notify the caller that the
     *                      system data was received or that an error was encountered.
     *                      If successful, return cooling fan speed as percentage of
     *                      maximum (range [0.0, 1.0]).
     *
     */
    export function getFanSpeed(callback: Callback<number>) {
        _getSystemSetting("fan_speed", callback);
    }

    /**
     * Get the robot's fan mode.
     * @method jibo.system#getFanMode
     * @param {Function} callback Notify the caller that the
     *                      system data was received or that an error was encountered.
     *                      If successful, return fan mode as a string.
     *
     */
    export function getFanMode(callback: Callback<string>) {
        _getSystemSetting("fan_mode", callback);
    }

    /**
     * Get LCD backlight information.
     * @method jibo.system#getBacklight
     * @param {Function} callback Notify the caller that the
     *                      system data was received or that an error was encountered.
     *                      If successful, return the LCD backlight brightness
     *                      in percentage of maximum (range [0.0, 1.0]).
     */
    export function getBacklight(callback: Callback<number>) {
        _getSystemSetting("lcd_backlight", callback);
    }

    /**
     * Set the LCD backlight brightness.
     * @method jibo.system#setBacklight
     * @param {Value} value Desired brightness of LCD backlight (range [0.0 - 1.0]).
     * @param {Function} callback Notify the caller that the
     *                      system data was received or that an error was encountered.
     *                      If unsuccessful, return the error; otherwise, return 'null'.
     */
    export function setBacklight(value: number, callback: Callback<void>) {
        // ensure that value is between 0.0 and 1.0
        if ((value < 0.0) || (value > 1.0)) {
            return callback(`Backlight brightness value of ${value} is out of range [0.0 - 1.0].`);
        }

        // get fan speed & fan mode so we can set current value in body (so we don't muck with it!)
        getFanMode((fanModeError, fanMode) => {
            if (fanModeError) {
                callback(fanModeError);
            } else {
                getFanSpeed((fanSpeedError, fan) => {
                    if (fanSpeedError) {
                        callback(fanSpeedError);
                    }
                    else {
                        const body = {
                            "lcd_backlight": value,
                            "fan_speed": fan,
                            "fan_mode": fanMode,
                        };
                        const request = new XMLHttpRequest();
                        const uri = bodyHttpInterface + '/settings';
                        request.open("POST", uri, true);
                        request.onreadystatechange = () => {
                            if (request.readyState === 4) {
                                if (request.status === 204) { // no content means success!
                                    callback(null);
                                }
                                else {
                                    // failure if anything else
                                    let message = 'Body service is unavailable';
                                    if (request.statusText !== undefined && request.statusText !== "") {
                                        message = request.statusText;
                                    }
                                    callback(message);
                                }
                            }
                        };

                        request.send(JSON.stringify(body));
                    }
                });
            }
        });

    }


    /**
     * Get current master volume.
     * @method jibo.system#getMasterVolume
     * @param {Function} callback Notify the caller that the
     *                      system data was received or that an error was encountered.
     *                      If successful, return the master volume (range [0.0, 1.0]).
     */
    export function getMasterVolume(callback: Callback<number>) {
        _getMixerSetting((error, settings) => {
            if (error) {
                callback(error);
            }
            else {
                callback(null, settings.master.playbackVolume);
            }
        });
    }

    /**
     * Set the master volume.
     * @method jibo.system#setMasterVolume
     * @param {number} value Desired master volume (range [0.0 - 1.0]).
     * @param {Function} cb Notify the caller that
     *                      system data was received or that an error was encountered.
     *                      If unsuccessful, return the error; otherwise, return `null`.
     */
    export function setMasterVolume(value: number, cb: Callback<void>) {
        if (isNaN(value)) {
            let error = value + ' is not a number. Please pick a value between [0.0 - 1.0].';
            cb(error);
            return;
        }

        // ensure that value is between 0.0 and 1.0
        if (value < 0.0 || value > 1.0) {
            let error = 'Master volume of ' + value + ' is out of range [0.0 - 1.0].';
            cb(error);
            return;
        }
        // get mixer settings so we can only alter the one property
        _getMixerSetting((error, settings) => {
            if (error) {
                cb(error);
            }
            else {
                let request = new XMLHttpRequest();
                let uri = audioHttpInterface + '/mixer';

                request.open("POST", uri, true);

                request.onreadystatechange = () => {
                    if (request.readyState === 4) {
                        if (request.status === 204) { // no content means success!
                            cb(null);
                        }
                        else {
                            // failure if anything else
                            let msg = 'Audio Service is unavailable';
                            if (request.statusText !== undefined && request.statusText !== "") {
                                msg = request.statusText; // use "reason" if they gave it
                            }

                            cb(msg);
                        }
                    }
                };

                settings.master.playbackVolume = value;
                request.send(JSON.stringify(settings));
            }
        });
    }

    /**
     * Initializes the audio system.
     * @param service {ServiceRecord} service record to initialize audio service.
     * @param callback {Function} Callback for once socket has been created.
     * @method jibo.system#initAudio
     */
    export function initAudio(service: ServiceRecord, parentLog: Log, callback: InitCallback) {
        audioHttpInterface = "http://" + service.host + ":" + service.port;
        _inputEnergy = {
            ts: [],         // Chronometer timestamp of this state
            db_rms: 0.0,    // Overall dB RMS of input waveform
            db_high: 0.0,   // ~1KHz dB RMS of input waveform
            db_mid: 0.0,    // ~500Hz dB RMS of input waveform
            db_low: 0.0     // ~200Hz dB RMS of input waveform
        };
        const audioSocketUrl = "ws:" + service.host + ":" + service.port;
        const energySocket = new WSClient(audioSocketUrl + "/input_energy");
        energySocket.on('error', () => {
            log.warn(`Error opening audio input energy socket at ${audioSocketUrl}/input_energy`);
        });
        energySocket.on('message', (data) => {
            _inputEnergy = data;
            events.inputEnergy.emit(_inputEnergy);
        });
        callback();
    }

    /**
     * Get mixer settings.
     * @method jibo.system#_getMixerSetting
     * @param {Function} cb Callback when complete.
     * @private
     */
    function _getMixerSetting(cb: Callback) {
        if (!audioHttpInterface) {
            cb('Audio Service is not available', null);
            return;
        }

        let request = new XMLHttpRequest();

        request.open("GET", audioHttpInterface + '/mixer', true);

        request.onreadystatechange = () => {
            if (request.readyState === 4) {
                if (request.status === 200) {
                    if (request.response) {
                        // success!
                        let response = JSON.parse(request.response);
                        cb(null, response);
                    }
                    else {
                        cb('No data received from audio service', null);
                    }
                }
                else {
                    // failure if anything else
                    let msg = 'Audio service is unavailable';
                    if (request.statusText !== undefined && request.statusText !== "") {
                        msg = request.statusText;
                    }

                    cb(msg, null);
                }
            }
        };
        request.send();
    }

    /**
     * Create the WS to misc information
     * @param callback {Function} Callback for once socket has been created
     * @method jibo.system#_createMiscSocket
     * @private
     */
    function _createMiscSocket(callback: InitCallback) {
        miscSocket = new WSClient(socketUrl + "/misc");
        miscSocket.on('error', () => {
            log.warn(`Error opening misc state socket at ${socketUrl}/misc`);
        });
        miscSocket.on('message', (data) => {
            bs.miscState = data;
            // The hatch was just opened
            if (data.hatch_open && !hatchOpen) {
                hatchOpen = true;
                log.debug("hatch open");
                events.hatchOpen.emit();
            }
            // the hatch isn't opened but it just closed
            else if (!data.hatch_open && hatchOpen) {
                hatchOpen = false;
                log.debug("hatch closed");
                events.hatchClose.emit();
            }
        });
        callback();
    }

    /**
     * Create the WS to touch information
     * @param callback {Function} Callback for once socket has been created
     * @method jibo.system#_createTouchSocket
     * @private
     */
    function _createTouchSocket(callback: InitCallback) {
        touchSocket = new WSClient(socketUrl + "/touch");
        touchSocket.on('error', () => {
            log.warn(`Error opening touch state socket at ${socketUrl}/touch`);
        });
        touchSocket.on('message', (data: TouchState) => {
            touchHandler.acceptTouch(data);
        });
        callback();
    }

    /**
     * Create the WS to power information
     * @param callback {Function} Callback for once socket has been created
     * @method jibo.system#_createPowerSocket
     * @private
     */
    function _createPowerSocket(callback: InitCallback) {
        powerSocket = new WSClient(socketUrl + "/power");
        powerSocket.on('error', () => {
            log.warn(`Error opening power state socket at ${socketUrl}/power`);
        });
        powerSocket.on('message', (data) => {
            bs.powerState = data;
            powerSource = powerSource || data.source;
            // we just went to battery state, but previously were plugged in
            if (bs.powerState.source === PowerSource.BATTERY && powerSource === PowerSource.EXTERNAL) {
                powerSource = PowerSource.BATTERY;
                log.debug("unplugged");
                events.unplugged.emit();
            }
            // we were just plugged in but now we're on battery
            else if (bs.powerState.source === PowerSource.EXTERNAL && powerSource === PowerSource.BATTERY) {
                powerSource = PowerSource.EXTERNAL;
                log.debug("plugged in");
                events.pluggedIn.emit();
            }
        });
        callback();
    }

    /**
     * Create axis state socket for axis events.
     * @method jibo.lps#_createAxisSocket
     * @param {Function} cb Callback for once axis has been created.
     * @private
     */
    function _createAxisSocket(cb: InitCallback) {
        let axisIsFaulting = false;
        axisSocket = new WSClient(socketUrl + "/axis_state");

        axisSocket.on('error', (/*err*/) => {
            log.warn(`Error opening axis state socket at ${socketUrl}/axis_state`);
        });
        axisSocket.on('message', (data: AxisState) => {
            // we're special and our data comes in
            // already JSON.Parse'd because of jibo-client-framework.
            const pelvisStatus = data.pelvis.fault_status; //1 is fault, 0 is safe
            const torsoStatus = data.torso.fault_status;
            const neckStatus = data.neck.fault_status;
            const isFaulting = pelvisStatus || torsoStatus || neckStatus;
            if (isFaulting && !axisIsFaulting) {
                axisIsFaulting = true;
                events.axisFaultOn.emit(data);
            }
            else if (!isFaulting && axisIsFaulting) {
                axisIsFaulting = false;
                events.axisFaultOff.emit();
            }
        });

        cb();
    }

    /**
     * Create axis state socket for axis events.
     * @method jibo.lps#_createIMUSocket
     * @param {Function} cb Callback for once axis has been created.
     * @private
     */
    function _createIMUSocket(cb: InitCallback) {
        imuSocket = new WSClient(socketUrl + "/imu");

        imuSocket.on('error', (/*err*/) => {
            log.warn(`Error opening axis state socket at ${socketUrl}/imu`);
        });
        imuSocket.on('message', (data: IMUState) => {
            bs.imuState = data;
            isMoving = isMoving || data.moving;

            if (data.moving && !isMoving) {
                isMoving = true;
                // log.debug("pick up");
                // events.pickUp.emit();
            }
            else if (isMoving && !data.moving) {
                isMoving = false;
                // log.debug("put down");
                // events.putDown.emit();
            }
        });

        cb();
    }

    /**
     * Get the current system setting for a given system
     * @param {string} setting the setting to get the information for.
     * @param {Function} callback Notify the caller that the robot was successfully indexed.
     *                      If unsuccessful, return the error; otherwise, return the setting value.
     * @method jibo.system#_getSystemSetting
     * @private
     */
    function _getSystemSetting(setting, callback: Callback) {
        if (bodyHttpInterface === undefined) {
            return callback('Body Service is not available', null);
        }
        const request = new XMLHttpRequest();
        request.open("GET", bodyHttpInterface + '/settings', true);
        request.onreadystatechange = () => {
            if (request.readyState === 4) {
                if (request.status === 200) {
                    if (request.response) {
                        // success!
                        const response = JSON.parse(request.response);
                        callback(null, response[setting]);
                    }
                    else {
                        callback('No data received from body service', null);
                    }
                }
                else {
                    // failure if anything else
                    let message = 'Body service is unavailable';
                    if (request.statusText !== undefined && request.statusText !== "") {
                        message = request.statusText;
                    }

                    callback(message, null);
                }
            }
        };

        request.send();
    }
}
