import * as async from 'async';
import { WSClient } from 'jibo-client-framework';
import {Event} from 'jibo-typed-events';
import {ServiceRecord, InitCallback, Callback} from '../utils/Types';
import {Log} from 'jibo-log';

let log:Log;

/**
 * @description
 * Text-to-Speech
 *
 * ```
 * var jibo = require("jibo");
 * jibo.tts.on('word', (word) => {
 *     //respond to words
 * });
 * jibo.tts.speak("Hello, my name is Jibo", (err) => {
 *
 * });
 * ```
 * @namespace jibo.tts
 */

/**
 * Enum for TTS modes.
 * @typedef jibo.tts#TTSMode
 * @property SSML {String} Advanced, allows use of SSML.
 * @property TEXT {String} Default.
 */
export enum TTSMode {
    SSML = "ssml",
    TEXT = "text",
}

/**
 * Enum for TTS locales.
 * @typedef jibo.tts#TTSLocale
 * @property EN_US {String} US English.
 */
export enum TTSLocale {
    EN_US = "en-us",
}

/**
 * Enum for TTS voices.
 * @typedef jibo.tts#TTSVoice
 * @property GRIFFIN {String} "Griffin" voice.
 * @intdocs
 */
export enum TTSVoice {
    GRIFFIN = "griffin",
}

/**
 * Enum for TTS "boolean" values.
 * @typedef jibo.tts#TTSBoolean
 * @property TRUE {String}
 * @property FALSE {String}
 */
export enum TTSBoolean {
    TRUE = "TRUE",
    FALSE = "FALSE",
}

/**
 * TTS Server API paths.
 * {@link https://confluence.jibo.com/display/ENG/TTS+Service|TTS Service Docs}
 * @private
 * @enum {String}
 */
const APIPath = {
    TOKENS: '/tts_tokens',
    PHONES: '/tts_phones',
    STOP: '/tts_stop',
    SPEAK: '/tts_speak',
    TIMING: '/tts_token_times',
    EFFECTS: '/tts_effects',
    ANALYSIS: '/tts_analysis',
    POS_TOKENS: '/tts_lex',
    POS_TAGGING: '/tts_pos_tagging'
};

/**
 * The various types of actions pedals can take.
 * @private
 * @enum {String}
 */
export enum PedalsActions {
    START = 'START',
    STOP = 'STOP',
    UPDATE = 'UPDATE'
}

export type TimingsCB = Callback<WordTimings>;
export type POSTokensCallback = Callback<POSTokens>;
export type POSTagsCallback = Callback<POSTags>;

export interface TTSOptions {
    duration_stretch?:number;
    pitch?:number;
    pitchBandwidth?:number;
    locale?:TTSLocale;
    voice?:TTSVoice;
    mode?:TTSMode;
    skipWordEvents?: TTSBoolean;
    volume?:number;
    whisper?:TTSBoolean;
    cached?:TTSBoolean;
    earlyStopTime?:number;  // Stop TTS synthesis (positive) seconds into request
}

// Currently no configuration options,
// Created in case there may be one in the future.
export interface POSOptions {}
export interface WordTimings {
    tokentimes: {
        tokens: {
            name: string,
            start: number,
            end: number
        }[];
    };
}
export interface POSTokens {
    tokens: string[];
}
export interface POSTags {
    tokentags: string[][]; // e.g., [["WORD", "NN"]]
}
export interface Word {
    token: string;
    timestamp: number;
    status: string;
    moreinfo: any[];
}

/**
 * The various events this service will emit.
 * @alias jibo.tts~PedalsEvents
 * @enum {String}
 */
//const PedalsEvents = {
//    CONNECT: 'connect',
//    DISCONNECT: 'disconnect',
//    CONNECT_FAIL: 'connect-fail',
//    ERROR: 'error'
//};

/**
 * The default settings for a TTS request body
 * @private
 */
const defaultTTSReqBody = {
    prompt: '',
    locale: TTSLocale.EN_US,
    voice: TTSVoice.GRIFFIN,
    mode: TTSMode.TEXT
};

/**
 * The default settings for a POS request body
 * @private
 */
const defaultPOSReqBody = {
    text: '',
    locale: TTSLocale.EN_US,
    tokens: []
};

/**
 * Emitted when a word is spoken.
 * @name jibo.tts#word
 * @type {TypedEvent}
 */
export const word:Event<Word> = new Event<Word>('Word');
/**
 * Emitted when a phoneme event happens
 * @name jibo.tts#phone
 * @type {TypedEvent}
 */
export const phone:Event<any> = new Event<any>('Phone');
/**
 * Emitted when an effect event happens
 * @name jibo.tts#effect
 * @type {TypedEvent}
 */
export const effect:Event<any> = new Event<any>('Effect');
/**
 * Emitted when an analysis event happens
 * @name jibo.tts#analysis
 * @type {TypedEvent}
 */
export const analysis:Event<any> = new Event<any>('Analysis');
/**
 * Emitted when TTS stops
 * @name jibo.tts#stopped
 * @type {TypedEvent}
 */
export const stopped:Event<void> = new Event<void>('Stopped');

export let isInitialized:boolean = false;
export let isTalking:boolean = false;
export let isStopping:boolean = false;

let effectsSocket:WSClient;
let httpInterface:string;
let socketUrl:string;

export function init(service:ServiceRecord, parentLog:Log, cb:InitCallback) {
    if (!service.host || typeof service.host !== 'string') {
        throw new Error(`Missing required service.host`);
    }
    log = parentLog.createChild("TTS");

    httpInterface = "http://" + service.host + ":" + service.port;
    socketUrl =  "ws:" + service.host + ":" + service.port;

    // Wrap effect socket call so we can extract socket and keep ref to it
    let effectsSocketCreator = (cb) => {
        let handler = (socket:WSClient) => {
            effectsSocket = socket;
            cb();
        };
        createSocket(APIPath.EFFECTS, "tts sound effects", effect)(handler);
    };

    async.parallel(
        [
            createSocket(APIPath.TOKENS, "tts tokens", word),
            createSocket(APIPath.PHONES, "tts phones", phone),
            createSocket(APIPath.ANALYSIS, "tts analysis", analysis),
            effectsSocketCreator
        ],
        () => {
            isInitialized = true;
            cb();
        }
    );
}

function createSocket(path:string, socketDescription:string, emitter:Event<any>) {
    return (cb:(socket:WSClient) => void) => {
        let socket = new WSClient(socketUrl + path);
        socket.on('error', () => {
            log.error(`Error opening ${socketDescription} socket at ${socketUrl}${path}`);
        });
        socket.on('message', (data) => {
            log.debug(data);
            if (data) {
                emitter.emit(data);
            }
        });
        cb(socket);
    };

}

/**
 * Make Jibo speak.
 * @method jibo.tts#speak
 * @param {String} text Text for Jibo to speak.
 * @param {Object} [options] Parameters to override default TTS behavior.
 * @param {number} [options.duration_stretch] Stretch the utterance. 1 = no stretch, 0.5 = halve the duration, 2 = double the duration. No upper limit.
 *                                            No effect if `options.mode === jibo.tts.TTSMode.SSML`.
 * @param {number} [options.pitch]  Control the overall pitch of the speaker. No SSML tag to override
 *                                  Recommended value is 0.42. The recommended range is [0.2, 0.8].
 * @param {number} [options.pitchBandwidth] Widen the pitch bandwidth. Recommended value is 1.
 *                                          The range is [0.0, 2.0]. `0` makes Jibo sound robotic. `2.0`
 *                                          makes Jibo sound more human.
 * @param {jibo.tts~TTSMode} [options.mode] In `jibo.tts.TTSMode.SSML` mode, the `text` argument to this function should contain valid SSML. In text mode, the prompt can contain any text.
 * @param {boolean} [options.skipWordEvents=false] If `true`, no word events are emitted during TTS synthesis.
 * @param {Function} [callback] Notify the caller that the speech has started. If no
 *                              callback is provided, return a `Promise`.
 * @return {Promise|undefined} If no callback is provided, return a `Promise`, which is resolved when done speaking.
 */
export function speak(text:string, options?:TTSOptions): Promise<void>;
export function speak(text:string, callback:Callback<void>): void;
export function speak(text:string, options:TTSOptions, callback:Callback<void>): void;
export function speak(text:string, arg1?, arg2?):void|Promise<void> {
    const { options, callback } = _getOptionsAndCallback<TTSOptions, Callback<void>>(arg1, arg2);

    const prom = new Promise<void>((resolve, reject) => {
        if (!isInitialized) {
            return reject('TTS service is not initialized!');
        }
        let doSpeak = () => {
            if (options.skipWordEvents) {
                _sendTTSRequest(text, options, (err, result) => {
                    if (err) {
                        reject(err);
                    } else {
                        resolve(result);
                    }
                });
            }
            else {
                // We start by getting the word schedule
                getWordTimings(text, options, (err, timings) => {
                    if (err) {
                        reject(err);
                    }
                    else {
                        // We then start dispatching the word schedule
                        // asynchronously
                        _dispatchWordSchedule(timings);
                        _sendTTSRequest(text, options, (err, result) => {
                            if (err) {
                                reject(err);
                            } else {
                                resolve(result);
                            }
                        });
                    }
                });
            }
        };

        if(isStopping) {
            stopped.once(() => {
                doSpeak();
            });
        }
        else if(isTalking) {
            stop(doSpeak);
        }
        else {
            doSpeak();
        }
    });
    if (typeof callback === 'function') {
        prom.then((result) => {
            callback(null);
        }, (err) => {
            callback(err);
        });
    } else {
        return prom;
    }

}

/**
 * Stop any speech Jibo is uttering.
 * @method jibo.tts#stop
 * @param {Function} [callback] Notify the caller that speech has stopped. If no callback is provided, return a `Promise`.
 * @return {Promise|undefined} If no callback is provided, return a `Promise`, which gets resolved when stopped.
 */
export function stop():Promise<void>;
export function stop(callback:Callback<void>):void;
export function stop(callback?:Callback<void>):void|Promise<void> {
    const prom = new Promise<void>((resolve, reject) => {
        if (!isInitialized) {
            return reject('TTS service is not initialized!');
        }
        isStopping = true;
        isTalking = false;
        let request = new XMLHttpRequest();
        request.timeout = 2000;
        request.onreadystatechange = () => {
            let requestIsDone = request.readyState === 4;
            let isErrorStatus = request.status < 200 || request.status >= 400;
            if(requestIsDone && request.status === 200) { // HTTP_OK
                isStopping = false;
                stopped.emit();
                resolve();
            } else if (requestIsDone && isErrorStatus) {
                isStopping = false;
                stopped.emit();
                reject(new Error(`TTS.stop request failed with status: ${request.status}`));
            }
        };
        request.open("GET", httpInterface + APIPath.STOP, true);
        request.send(null);
    });
    if (typeof callback === 'function') {
        prom.then((result) => {
            callback(null);
        }, (err) => {
            callback(err);
        });
    } else {
        return prom;
    }
}

/**
 * Asynchronously retrieve a word schedule for given text (SSML markup support coming soon!).
 * @method jibo.tts#getWordTimings
 * @param {String} text The utterance provided to TTS for speaking.
 * @param {Object} [options] Same options as {@link jibo.tts#speak}.
 * @param {Function} [callback] Callback. If none is provided, return a `Promise`.
 * @return {Promise|undefined}
 */
export function getWordTimings(text:string, options?:TTSOptions): Promise<WordTimings>;
export function getWordTimings(text:string, callback:TimingsCB): void;
export function getWordTimings(text:string, options:TTSOptions, callback:TimingsCB): void;
export function getWordTimings(text:string, arg1?, arg2?):void|Promise<WordTimings> {
    const { options, callback } = _getOptionsAndCallback<TTSOptions, TimingsCB>(arg1, arg2);
    const prom = new Promise<WordTimings>((resolve, reject) => {
        if (!isInitialized) {
            return reject('TTS service is not initialized!');
        }
        if (typeof text !== 'string') {
            throw new TypeError(`Invalid params: ${text}, ${TTSMode}`);
        }

        let request = new XMLHttpRequest();

        let requestBody = JSON.parse(JSON.stringify(defaultTTSReqBody));
        requestBody.prompt = text;

        // Pass in optional parameters
        requestBody.duration_stretch = options.duration_stretch ||
          requestBody.duration_stretch;
        requestBody.pitchBandwidth = options.pitchBandwidth ||
          requestBody.pitchBandwidth;
        requestBody.pitch = options.pitch || requestBody.pitch;
        requestBody.mode = options.mode || requestBody.mode;
        requestBody.cached = options.cached || requestBody.cached;

        // Create actual request body and subscribe response handler
        requestBody = JSON.stringify(requestBody);
        request.open('POST', httpInterface + APIPath.TIMING, true);
        request.onreadystatechange = () => {
            let requestIsDone = request.readyState === 4;
            let isErrorStatus = request.status < 200 || request.status >= 400;
            if(requestIsDone && request.status === 200) {
                // We attempt parsing the message
                let msg;
                try{
                    msg = JSON.parse(request.response);
                } catch(err){
                    reject(err);
                }
                if (msg) {
                    if (msg.Status && msg.Status === 'ERROR') {
                        reject(msg);
                    }
                    else {
                        resolve(msg);
                    }
                }
            } else if (requestIsDone && isErrorStatus) {
                reject(new Error(`Request failed with status: ${request.status}`));
            }
        };
        request.send(requestBody);
    });
    if (typeof callback === 'function') {
        prom.then((result) => {
            callback(null, result);
        }, (err) => {
            callback(err);
        });
    } else {
        return prom;
    }
}

/**
 * Start a sound effect.
 * @method jibo.tts#startEffect
 * @param {String} name The name of the effect.
 * @param {number | string} value Either a number between 0 and 1 or a
 * string parameter for the effect.
 */
export function startEffect(name:string, value:string|number): void {
    _validateEffectNameParam(name);
    _validateEffectValueParam(value);

    let requestBody = {
        'name': name,
        'action': PedalsActions.START,
        'param': ("" + value)
    };
    effectsSocket.send(JSON.stringify(requestBody));
}

/**
 * Stop a sound effect.
 * @method jibo.tts#stopEffect
 * @param {String} name The name of the effect.
 */
export function stopEffect(name:string): void {
    _validateEffectNameParam(name);

    let requestBody = {
        'name': name,
        'action': PedalsActions.STOP,
        'param': "0"
    };
    effectsSocket.send(JSON.stringify(requestBody));
}

/**
 * Update the value of a sound effect.
 * @method jibo.tts#updateEffect
 * @param {String} name The name of the effect.
 * @param {number | string} value Either a number between 0 and 1 or a
 * string parameter for the effect.
 */
export function updateEffect(name:string, value:string|number): void {
    _validateEffectNameParam(name);
    _validateEffectValueParam(value);

    let requestBody = {
        'name': name,
        'action': PedalsActions.UPDATE,
        'param': ("" + value)
    };
    effectsSocket.send(JSON.stringify(requestBody));
}

/**
 * Tokenize a string
 * @method jibo.tts#getPOSTokens
 * @param {string} text The text to be tokenized.
 * @param {Object} [options] Parameters to override the default POS behavior.
 * @param {Function} [callback] Notify the caller about the resulting tokens
 *
 * @return {Promise|undefined} If no callack is provided, return a `Promise`, which is resolved when done tokenizing.
 */
export function getPOSTokens(text:string, options?:POSOptions): Promise<POSTokens>;
export function getPOSTokens(text:string, callback:POSTokensCallback): void;
export function getPOSTokens(text:string, options:POSOptions, callback:POSTokensCallback): void;
export function getPOSTokens(text: string, arg1?, arg2?): void|Promise<POSTokens> {
    const { callback } = _getOptionsAndCallback<POSOptions, POSTokensCallback>(arg1, arg2);
    const prom = new Promise<POSTokens>((resolve, reject) => {
        if (!isInitialized) {
            return reject('TTS service is not initialized!');
        }
        if (typeof text !== 'string') {
            throw new TypeError(`Invalid params: ${text}, ${TTSMode}`);
        }

        // Guard against empty string.
        if (text === "") {
            let response = {
              tokens: []
            };
            resolve(response);
            return;
        }

        let requestBody = JSON.parse(JSON.stringify(defaultPOSReqBody));
        requestBody.text = text;
        requestBody = JSON.stringify(requestBody);
        let url = httpInterface + APIPath.POS_TOKENS;
        _sendPOSRequest(requestBody, url, (err, result) => {
            if (err) {
                reject(err);
            } else {
                resolve(result);
            }
        });
    });
    if (typeof callback === 'function') {
        prom.then((result) => {
            callback(null, result);
        }, (err) => {
            callback(err);
        });
    } else {
        return prom;
    }
}

/**
 * Get POS Tags from a list of tokens (including words, symbols, etc)
 * @method jibo.tts#getPOSTags
 * @param {string[]} tokens A list of tokens (including words and symbols)
 * @param {Object} [options] Parameters to override default POS behavior.
 * @param {Function} [callback] Notify the caller about the resulting POS tags
 *
 * @return {Promise|undefined} If no callback if provided, return a `Promise`, which is resolved when finishing tagging.
 */
export function getPOSTags(tokens: string[], options?:POSOptions): Promise<POSTags>;
export function getPOSTags(tokens: string[], callback:POSTagsCallback): void;
export function getPOSTags(tokens: string[], options:POSOptions, callback:POSTagsCallback): void;
export function getPOSTags(tokens: string[], arg1?, arg2?): void|Promise<POSTags> {
    const { callback } = _getOptionsAndCallback<POSOptions, POSTagsCallback>(arg1, arg2);
    const prom = new Promise<POSTags>((resolve, reject) => {
        if (!isInitialized) {
            return reject('TTS service is not initialized!');
        }
        if (tokens.length === 0) {
            let response = {
                tokentags: []
            };
            resolve(response);
            return;
        }
        let requestBody = JSON.parse(JSON.stringify(defaultPOSReqBody));
        requestBody.tokens = tokens;
        requestBody = JSON.stringify(requestBody);
        let url = httpInterface + APIPath.POS_TAGGING;
        _sendPOSRequest(requestBody, url, (err, result) => {
            if (err) {
                reject(err);
            } else {
                resolve(result);
            }
        });
    });
    if (typeof callback === 'function') {
        prom.then((result) => {
            callback(null, result);
        }, (err) => {
            callback(err);
        });
    } else {
        return prom;
    }
}

function _getOptionsAndCallback<O, T extends Function>(arg1:O|T, arg2?:T) {
    let options: O = <O>{};
    let callback: T;
    if (!arg1 && !arg2) {
        options = <O>{};
    }
    else if (typeof arg1 === 'object' && !arg2) {
        options = arg1;
    }
    else if (typeof arg1 === 'function' && !arg2) {
        callback = arg1;
    }

    else if (typeof arg1 === 'object' && typeof arg2 === 'function') {
        options = arg1;
        callback = arg2;
    }
    return {
        options, callback
    };
}

function _dispatchWordSchedule(wordTimings:WordTimings) {
    let start = Date.now();
    let index = 0;
    let timings = wordTimings.tokentimes.tokens
        .filter(token => (token.name !== '/pau/' &&
                          token.name !== '<break>' &&
                          token.name !== '<audioBreak>' &&
                          token.name !== '<say-as>' &&
                          token.name !== '[lpau]') );

    let handleWord = () => {
        let wordObj = timings[index];
        word.emit({
            token: wordObj.name,
            timestamp: wordObj.start,
            status: 'PLAY',
            moreinfo: []
        });
        index++;
        if (index < timings.length) {
            let nextTime = 1000 * timings[index].start;
            let current = Date.now() - start;
            setTimeout(handleWord, Math.max(nextTime - current, 0));
        }
    };

    if (timings.length) {
        let nextTime = 1000 * timings[index].start;
        setTimeout(handleWord, nextTime);
    }
}

function _sendPOSRequest(payload:string, url:string, callback:Callback) {
    let request = new XMLHttpRequest();
    request.open('POST', url, true);
    request.onreadystatechange = () => {
        let requestIsDone = request.readyState === 4;
        if (requestIsDone) {
            if (request.status === 200) {
                try {
                    let response = JSON.parse(request.response);
                    callback(null, response);
                } catch (err) {
                    callback(err);
                }

            } else {
                callback(new Error(`Request failed with status: ${request.status}`));
            }
        }
    };
    request.send(payload);
}

function _sendTTSRequest(text:string, options:TTSOptions, callback:Callback) {
    let request = new XMLHttpRequest();

    let requestBody = JSON.parse(JSON.stringify(defaultTTSReqBody));
    requestBody.prompt = text;

    // Pass in optional parameters
    if (options.duration_stretch) {
        requestBody.duration_stretch = options.duration_stretch;
    }
    if (options.pitchBandwidth) {
        requestBody.pitchBandwidth = options.pitchBandwidth;
    }
    if (options.pitch) {
        requestBody.pitch = options.pitch;
    }
    if (options.volume) {
        requestBody.volume = options.volume;
    }
    if (options.whisper) {
        requestBody.whisper = options.whisper;
    }
    if (options.cached) {
        requestBody.cached = options.cached;
    }
    if (options.earlyStopTime) {
        requestBody.earlyStopTime = options.earlyStopTime;
    }

    requestBody.mode = options.mode || requestBody.mode;

    requestBody = JSON.stringify(requestBody);
    request.open("POST", httpInterface + APIPath.SPEAK, true);

    request.onreadystatechange = () => {
        if (request.readyState === 4) {
            if (request.status === 204) { // HTTP_NO_CONTENT
                isTalking = false;
                callback();
            }
            else {
                // failure if anything else
                let msg = 'TTS Service is unavailable';
                if (request.statusText !== undefined && request.statusText !== "") {
                    msg = request.statusText; // use "reason" if they gave it
                }
                callback(msg);
            }
        }
    };
    isTalking = true;
    request.send(requestBody);
}

function _validateEffectNameParam(name:string): void {
    if (typeof name !== 'string') {
        throw new TypeError(`Invalid params, name must be string: ${name}`);
    }
    if (!effectsSocket) {
        throw new Error('Effect socket not initialized.');
    }
}

function _validateEffectValueParam(value:string|number): void {
    if (typeof value === 'number') {
        if (value < 0 || value > 1) {
            throw new TypeError(`Value out of range [0, 1]: ${value}`);
        }
    }
    else if(typeof value !== 'string') {
        throw new TypeError(`Value must either be a number or string: ${value}`);
    }
}
