import {HTTPClient} from 'jibo-client-framework';
import {Log} from 'jibo-log';
import {ServiceRecord, InitCallback} from '../utils/Types';


let mediaServiceUrl:string;
let http:HTTPClient;
let httpUrl:string;
let isInitialized:boolean = false;
let _recording:boolean = false;

/** Media Service. Internal Only.
 *
 * @class MediaService
 * @memberof jibo.media
 * @intdocs
 */
export class media {
    /** `true` if a recording is in progress.
     *
     * **Example**
     * ```
     * // Don't start a recording while one is progress
     * if( jibo.media.MediaService.recording === false ){
     *     // Disable record button
     * }
     * ```
     * @name jibo.media.MediaService.recording
     * @type {boolean}
     * @readOnly
     * @intdocs
     * @private
     */
    // not ready for prime time yet
    public static get recording(){
        return _recording;
    }
}

export namespace media {
    /** Enum of photo types.
     * @name jibo.media#PhotoType
     * @type {Enum}
     * @property DEBUG   {Number} 0; 1/2-scale (640x360) grayscale.
     * @property PREVIEW {Number} 1; 1/2-scale (640x360) color.
     * @property HALF    {Number} 1; alias for PREVIEW
     * @property SNAP    {Number} 2; Full-scale (1280x720) color. (default)
     * @property FULL    {Number} 2; alias for SNAP
     * @property FOUR_MP {Number} 3; Four megapixel (2688x1520) color.
     * @property LARGE   {Number} 3; alias for FOUR_MP
     */
    export enum PhotoType {
        DEBUG   = 0,
        PREVIEW = 1,
        HALF    = 1,  // alias for PREVIEW
        SNAP    = 2,
        FULL    = 2,  // alias for SNAP
        FOUR_MP = 3,
        LARGE   = 3   // alias for FOUR_MP
    }

    /** Enum of cameras.
     * @name jibo.media#CameraID
     * @type {Enum}
     * @property LEFT {Number} 0; Left camera.
     * @property RIGHT {Number} 1; Right camera. Default.
     */
    export enum CameraID {
        LEFT  = 0,
        RIGHT = 1
    }

    /**
     * @interface jibo.media~Filter
     * @property {string} kind
     * @property {any} config
     * @intdocs
     */
    export interface Filter {
        kind: string;
        config: any;
    }

    export interface PhotoResponse {
        id:string;
        previewUrl:string;
    }

    export interface Thumbnails {
        [name:string]:[number, number];
    }

    export interface ThumbnailsResponse {
        [name:string]:string;  // uuid for each thumbnail
    }

    export interface PhotoStoreResponse {
        id:string;
        thumbnails:ThumbnailsResponse;
        stored:boolean;
    }

    /** @callback jibo.media.MediaService~PhotoCallback */
    export type PhotoCallback = (err:Error, response?:PhotoResponse) => void;
    /** @callback jibo.media.MediaService~PhotoStoreCallback */
    export type PhotoStoreCallback = (err:Error, response?:PhotoStoreResponse) => void;

    export function init(service:ServiceRecord, parentLog:Log, cb:InitCallback) {
        if (!service.host || typeof service.host !== 'string') {
            throw new Error(`Missing required service.host`);
        }
        mediaServiceUrl = "http://" + service.host + ":" + service.port;
        isInitialized = true;

        http = new HTTPClient(service.host, service.port);
        httpUrl = "http://" + service.host + ":" + service.port;
        process.nextTick(cb);
    }


    /** Take a photo. Returns content id of photo.
     * Use `getPreviewUrl(data.id)` for
     * image url.
     *
     * @method jibo.media.MediaService#takePhoto
     * @param {jibo.media#CameraID} camera Camera to use.
     * @param {jibo.media#PhotoType} photoType Type of photo requested.
     * @param {jibo.media~Filter[]} [params.filters] List of filters to apply
     * to the image in order.
     * @param {boolean} store If `true`, image is also permanently
     * stored (currently ignored, use `storePhoto()`)
     * @param {jibo.media.MediaService~PhotoCallback} callback Called with an error, or
     * with data about the photo including the content ID (`data.id`).
     * @intdocs
     */
    export function takePhoto(camera:CameraID, photoType:PhotoType, filters:Filter[], store:boolean, callback:PhotoCallback) {
        if (!isInitialized) {
            return callback(new Error('Service not initialized'));
        }
        if (camera !== CameraID.LEFT && camera !== CameraID.RIGHT) {
            camera = CameraID.RIGHT; // default
        }

        if (photoType === undefined || (photoType < PhotoType.DEBUG || photoType > PhotoType.FOUR_MP)) {
            photoType = PhotoType.SNAP; // default
        }

        if (!filters) {
            filters = [];
        }

        let data = {
            'camera':    camera,     // One of 0, 1; signifying camera id, typically 0 is left and 1 is right
            'type':      photoType,  // One of (0, 1, 2, 3) meaning (DEBUG, half scale Y), (PREVIEW, half scale RGB), (SNAP, full scale RGB), (FOUR_MP, four megapixel RGB) respectively
            'filters': filters // undistort, flip, and other manipulation post platform 5.6.0
        };

        http.postJSON('/media/photo', data, (err:Error, response:PhotoResponse) => {
            if (err) {
                callback(err);
            } else {
                callback(null, response);
            }
        });
    }


    /** Store a photo and thumbnails to disk and return the UUID of
     * each saved image.
     *
     * @param {Buffer} buffer The image buffer to save to disk,
     * @param {object} thumbnails Keys are id to associate with that thumbnail. Values are two element Arrays, where the
     *                            first element is the width of the thumbnail, and the second is the height in pixels.
     * @param {jibo.media.MediaService~PhotoStoreCallback} callback Called when photos are stored.
     * @method jibo.media.MediaService#storePhoto
     * @intdocs
     */
    export function storePhoto(buffer:Buffer, id:string, thumbnails:Thumbnails, callback:PhotoStoreCallback) {
        let data = {
            buffer: buffer && buffer.toString('base64'),
            id: id || '',
            thumbnails: thumbnails
        };

        http.postJSON('/media/photo/store', data, (err:Error, response:PhotoStoreResponse) => {
            if (err) {
                callback(err);
            } else {
                callback(null, response);
            }
        });
    }

    /** Get a URL given a photo ID.
     *
     * @param {string} id ID of the photo.
     * @returns {string} URL to the photo.
     * @method jibo.media.MediaService#getUrl
     * @intdocs
     */
    export function getUrl(id:string):string {
        return mediaServiceUrl + `/media/photo/get?id=${id}`;
    }


    /** Get the preview URL of a recently taken
     * in-memory photo that hasn't been stored yet.
     *
     * @param {string} id Content ID of the photo.
     * @returns {string} URL to the photo.
     * @method jibo.media.MediaService#getPreviewUrl
     * @intdocs
     */
    export function getPreviewUrl(id:string):string {
        return mediaServiceUrl + `/media/photo?id=${id}`;
    }


    /** Set up a viewfinder in a window with camera preview positioned
     * at a given location on-screen.
     *
     * @method jibo.media.MediaService#setViewfinder
     * @param data {Object} Options for the viewfinder preview.
     * @param data.enable {Boolean} `true` to show viewfinder; `false` to not show viewfinder.
     * @param [data.width=1280] {Number} Width of the viewfinder.
     * @param [data.height=720] {Number} Height of the viewfinder.
     * @param [data.x=0] {Number} x-coordinate to place the viewfinder.
     * @param [data.y=0] {Number} y-coordinate to place the viewfinder.
     * @param [data.camera=1] {Number} Camera to use. 0=Left, 1=Right.
     * @param callback {Function} Callback for the method.
     * @intdocs
     */
    export function setViewfinder(data, callback) {
        if (!isInitialized) {
            return callback(new Error('Service not initialized'));
        }
        let params:any = {};

        // enable is a required parameter - if not present, return immediately
        if (!data.hasOwnProperty('enable')){
            callback("Preview service data must have 'enable' property", null);
            return;
        }

        // these are NOT required parameters - if not present, use defaults
        if (!data.hasOwnProperty('width')){ data.width = 1280;}
        if (!data.hasOwnProperty('height')){ data.height = 720;}
        if (!data.hasOwnProperty('x')){ data.x = 0;}
        if (!data.hasOwnProperty('y')){ data.y = 0;}
        if (!data.hasOwnProperty('camera')){ data.camera = CameraID.RIGHT;}

        params.enable = data.enable;
        params.camera = data.camera;
        params.window = {
            width: data.width,
            height: data.height,
            x: data.x,
            y: data.y
        };

        let request = new XMLHttpRequest();
        request.open("POST", httpUrl + '/media/preview/control', true);
        request.onreadystatechange = () => {
            if (request.readyState === 4) {
                if (request.status >= 200 && request.status <= 299) {
                    //if (request.response) {
                    //    // success!
                    //    let response = JSON.parse(request.response);
                    //    callback(null, response);
                    //}
                    //else {
                    //    callback('No data received from preview service', null);
                    //}
                    callback(); // @NOTE: uncomment above when a response is returned
                }
                else {
                    // failure if anything else
                    let msg = 'Preview service unavailable';
                    if(request.statusText !== undefined && request.statusText !== "") {
                        msg = request.statusText;
                    }

                    callback(msg, null);
                }
            }
        };
        request.send(JSON.stringify(params));
    }


    /** Get the current state of the viewfinder preview window.
     *
     * @method jibo.media.MediaService#getViewfinder
     * @param {Function} callback Callback for the function that returns an error, or
     * if request is successful returns object with timestamp, enable, and window.
     * @intdocs
     */
    export function getViewfinder(callback) {
        if (!isInitialized) {
            return callback(new Error('Service not initialized'));
        }
        let request = new XMLHttpRequest();

        request.open("GET", httpUrl + '/media/preview/control', true);

        request.onreadystatechange = () => {
            if (request.readyState === 4) {
                if (request.status >= 200 && request.status <= 299) {
                    if (request.response) {
                        // success!
                        let response = {};
                        try {
                            response = JSON.parse(request.response);
                            callback(null, response);
                        }
                        catch (e) {
                            callback(e);
                        }
                    }
                    else {
                        callback('No data received from media service', null);
                    }
                }
                else {
                    // failure if anything else
                    let msg = 'Preview service unavailable';
                    if(request.statusText !== undefined && request.statusText !== "") {
                        msg = request.statusText;
                    }

                    callback(msg, null);
                }
            }
        };

        request.send();
    }


    /** Start recording audio and/or video.
     *
     * **Example**
     * ```
     * jibo.media.MediaService.startRecording({
     *      audio: {},
     *      video: { width: 1280, height: 720 }
     * }, (err, recordingInfo) => {
     *     if(err){
     *         // Handle error
     *         return;
     *     }
     *
     *     // Save the id for playback later
     *     const recordingId = recordingInfo.id
     * });
     * ```
     *
     * @param {Object} options Options to configure the recording.
     * @param {Object} [options.audio] If provided, audio will be recorded.
     * @param {Object} [options.video] If provided, video will be recorded.
     * @param {Object} [options.video.width=640] The width the recorded video should be.
     * @param {Object} [options.video.height=360] The height the recorded video should be.
     * @param {Function} callback   Return an error or information about the started recording in the form {id: <recordingId> }.
     * @method jibo.media.MediaService#startRecording
     * @intdocs
     * @private
     */
    // not ready for prime time yet
    export function startRecording( options, callback ) {
        if( _recording === true ) {
            throw new Error("jibo.media.MediaService.startRecording() was called twice. Call jibo.media.MediaService.stopRecording() before calling it again.");
        }

        let payload:any = {
                "meta": {}
            };

        if( options.audio ) {
            payload.audioRec = {
                volume: 1,
                source: "ASRIn.monitor"
            };
        }

        if( options.video ) {
            payload.videoRec = {
                width: options.video.width || 640,
                height: options.video.height || 360
            };
        }

        _recording = true;
        _stopRecording( (err) => {
            if ( err ) {
                callback(err);
                return;
            }

            http.postJSON("/media/recording/start", payload, (err, response) => {
                if(err){
                    callback(err);
                    return;
                }
                callback(null, {
                    id: response.id
                });
            });
        });
    }


    /** Stop an in-progress recording.
     *
     * **Example**
     * ```
     * jibo.media.MediaService.stopRecording( (err, recordingInfo) => {
     *     if(err){
     *         // Handle error
     *         return;
     *     }
     *     // Optionally play back the recording now using `jibo.media.MediaService.playRecording(...)`
     * });
     * ```
     * @param {Function} callback   Provide notification when recording stops
     *                              or an error if something went wrong.
     * @method jibo.media.MediaService#stopRecording
     * @intdocs
     * @private
     */
    // not ready for prime time yet
    export function stopRecording( callback ) {
        if( _recording === false ) {
            throw new Error("jibo.media.MediaService.stopRecording() was called when there was no recording in progress.");
        }

        _stopRecording( (err) => {
            _recording = false;

            if ( err ) {
                callback(err);
                return;
            }

            callback(null);
        });
    }


    /** Play back a previous recording.
     *
     * **Example**
     * ```
     * jibo.media.MediaService.playRecording( { id: "<recordingId>" }, (err) => {
     *     if(err){
     *         // Handle error
     *         return;
     *     }
     *
     *     // Re-enable the playback button
     * });
     * ```
     *
     * @param {Object} options Options to configure the playback.
     * @param {Object} options.id ID of a known recording. See {@link jibo.media.MediaService#startRecording} for how to get an ID.
     * @param {Function} callback   Return when the playback is successfully started or an error
     *                              if something went wrong. Note: There are no playback controls, such as stop/pause/unpause. Coming soon.
     * @method jibo.media.MediaService#playRecording
     * @intdocs
     * @private
     */
    // not ready for prime time yet
    export function playRecording( options, callback ) {
        let payload = {
                source : options.id,
                audio : {
                    volume : 1
                }
            };

        http.postJSON("/media/recording/play", payload, (err, response) => {
            if(err){
                callback(err);
                return;
            }
            callback(null);
        });
    }


    /** Internal implementation of stopRecording. This one is difference than the main
     * implementation in that it doesn't throw errors when developers call it when
     * no recording was in progress. This is used by startRecording(), which calls
     * the robot media service to stop any rogue recording that might have been left running.
     * TODO: The robot media service should auto timeout or support auto stopping when
     * recording/start is called. Jira ticket here:
     * https://jira.jibo.com/browse/PLATSVCS-758
     * @private
     */
    function _stopRecording( callback ) {
        let payload = {
                id: 0,
                cmd:"stop"
            };

        http.postJSON("/media/recording/control", payload, (err) => {
            if ( err ) {
                callback(err);
                return;
            }

            callback(null);
        });
    }
}
