/**
 * Wifi interface for the robot.
 * @namespace jibo.wifi
 * @intdocs
 */
let _httpInterface:string;
let _wsInterface:string;
let _initialized:boolean = false;
let _isConnected:boolean = false;

/**
 * Initialize the wifi module for `jibo.init`.
 * @method jibo.wifi#init
 * @param service {Object} The service options
 * @param service.host {String} host name
 * @param service.port {String} port number
 * @param callback {Function} callback
 */
export function init(service:ServiceRecord, parentLog:Log, callback:InitCallback):void {
    log = parentLog.createChild("WifiService");
    _httpInterface = "http://" + service.host + ":" + service.port;
    _wsInterface = "ws:" + service.host + ":" + service.port;
    _initialized = true;

    callback();
    // create our event socket
    //_createEventSocket(callback);
}

/**
 * Gets our full internet connection status, using the value of the most recent verifyConnection()
 * call. Only use this if you recently did a verifyConnection and don't want to potentially keep
 * waiting for a verifyConnection() failure.
 * @method jibo.wifi#isConnected
 * @return {boolean} If we are currently connected.
 * @intdocs
 */
export function isConnected():boolean {
    return _isConnected;
}

/**
 * Add a wifi network.
 * @method jibo.wifi#addNetwork
 * @param networkData {Object} The network data
 * @param minVerifyTime {Integer} The minimum amount of time in seconds to verify the connection before failing
 * @param callback {Function} callback
 * @intdocs
 */
export function addNetwork(networkData:NetworkData, minVerifyTime:number, callback:ErrorCodeCallback):void {
    log.info('addNetwork called');
    let data = {
        networkData: networkData,
        minVerifyTime: minVerifyTime
    };
    _sendWifiCommandWithErrorCode('/add_network', data, callback);
}

/**
 * Select (enable) a wifi network.
 * @method jibo.wifi#selectNetwork
 * @param ssid {String} The network name
 * @param callback {Function} callback
 * @intdocs
 */
export function selectNetwork(_ssid:string, callback:Callback<void>):void {
    let data = {
        ssid: _ssid
    };
    _sendWifiCommand('/select_network', data, callback);
}

/**
 * Remove a wifi network.
 * @method jibo.wifi#removeNetwork
 * @param ssid {String} The network name
 * @param callback {Function} callback
 * @intdocs
 */
export function removeNetwork(_ssid:string, callback:Callback<void>):void {
    let data = {
        ssid: _ssid
    };
    _sendWifiCommand('/remove_network', data, callback);
}

/**
 * Remove all wifi networks.
 * @method jibo.wifi#removeAllNetworks
 * @param callback {Function} callback
 * @intdocs
 */
export function removeAllNetworks(callback:Callback<void>):void {
    _sendWifiCommand('/remove_all', null, callback);
}

/**
 * Get current network stats.
 * @method jibo.wifi#getCurrentNetwork
 * @param callback {Function} callback
 * @intdocs
 */
export function getCurrentNetwork(callback:Callback<NetworkStats>):void {
    _getWifiData('/get_current_network', (error:Error, response?:any) => {
        if (error) {
            return callback(error);
        }

        callback(null, response.stats);
    });
}

/**
 * Get currently saved networks.
 * @method jibo.wifi#getSavedNetworks
 * @param callback {Function} callback
 * @intdocs
 */
export function getSavedNetworks(callback:Callback<SavedNetworkEntry[]>):void {
    _getWifiData('/get_saved_networks', (error:Error, response?:any) => {
        if (error) {
            return callback(error);
        }

        callback(null, response.networks);
    });
}

/**
 * Verify the current network connection if network exists.
 * @method jibo.wifi#verifyConnection
 * @param callback {Function} callback
 * @intdocs
 */
export function verifyConnection(callback:ErrorCodeCallback): void {
    _sendWifiCommandWithErrorCode('/verify_connection', null, (err) => {
        _isConnected = !err;
        callback(err);
    });
}

function _sendWifiCommandWithErrorCode(path:string, data:any, callback:ErrorCodeCallback) {
    if(!_initialized) {
        callback({ code: 666, description: "Wifi service is unavailable" });
        return;
    }

    let request:XMLHttpRequest = new XMLHttpRequest();
    request.open("POST", _httpInterface + path, true);

    request.onreadystatechange = () => {
        // request is complete
        if(request.readyState === 4) {
            // "OK" status
            if(request.status === 200) {
                callback();
            }
            else {
                // failure if anything else
                let response;
                try {
                    response = JSON.parse(request.response);
                }
                catch(err) {
                    log.error('_sendWifiCommandWithErrorCode JSON Parse error: ', err, ' request: ', request.response);
                    response = err;
                }
                callback(response);
            }
        }
    };

    if(data) {
        request.send(JSON.stringify(data));
    }
    else {
        request.send();
    }
}


function _sendWifiCommand(path:string, data:any, callback:Callback<void>) {
    if(!_initialized) {
        callback(new Error("Wifi service is unavailable"));
        return;
    }

    let request:XMLHttpRequest = new XMLHttpRequest();
    request.open("POST", _httpInterface + path, true);

    request.onreadystatechange = () => {
        // request is complete
        if(request.readyState === 4) {
            // "OK" status
            if(request.status === 200) {
                callback();
            }
            else {
                // failure if anything else
                let response;
                let error;
                try {
                    response = JSON.parse(request.response);
                    error = response.error;
                }
                catch(err) {
                    log.error('_sendWifiCommand JSON Parse error: ', err, ' request: ', request.response);
                    error = err;
                }

                callback(new Error(error));
            }
        }
    };

    if(data) {
        request.send(JSON.stringify(data));
    }
    else {
        request.send();
    }
}


function _getWifiData(path:string, callback:Callback):void {
    if(!_initialized) {
        callback(new Error("Wifi service is unavailable"));
        return;
    }

    let request:XMLHttpRequest = new XMLHttpRequest();
    request.open("POST", _httpInterface + path, true);

    request.onreadystatechange = () => {
        // request is complete
        if(request.readyState === 4) {
            if(request.readyState === 4) {
                let response;
                let error;
                try {
                    response = JSON.parse(request.response);
                    error = response.error;
                }
                catch(err) {
                    error = err;
                    log.error('_getWifiData JSON Parse error: ', err, ' request: ', request.response);
                }

                // "OK" status
                if(request.status === 200) {
                    callback(null, response);
                }
                else {
                    // failure if anything else
                    callback(new Error(error));
                }
            }
        }
    };

    request.send();
}


