//
// Custom declarations, types and interfaces
//
export type ErrorCodeCallback = (err?:{ code:number; description:string;}) => void;

// @TODO - needs documentation
export enum NetworkType {
    DHCP,     // 0
    STATIC    // 1
}

export interface StaticNetworkSettings {
    staticIP:string;
    gateway:string;
    netmask:string;
    dns1?:string;
    dns2?:string;
}

export interface NetworkData {
    ssid:string;
    pswd:string;
    security:string;
    hidden:number;
    networkType:NetworkType;
    staticSettings:StaticNetworkSettings;
}

export interface NetworkStats {
    ssid: string;
    strength: number;
    speed: number;
    ip_address: string;
}

export interface SavedNetworkEntry {
    index: string;
    ssid: string;
    current: boolean;
    enabled: boolean;
}
