import {Log} from 'jibo-log';
import {ServiceRecord, InitCallback} from '../utils/Types';
/**
 * Measuring performance of different calls.
 * @namespace jibo.performance
 * @intdocs
 */
let httpInterface:string;
let initialized:boolean = false;

/**
 * Initialize the performance module for `jibo.init`.
 * @method jibo.performance#init
 * @param service {Object} The service options
 * @param service.host {String} host name
 * @param service.port {String} port number
 * @param callback {Function} callback
 */
export function init(service:ServiceRecord, parentLog:Log, callback:InitCallback):void {
    httpInterface = "http://" + service.host + ":" + service.port;
    initialized = true;
    callback();
}

/**
 * Post a log to the performance service.
 * @method jibo.performance#log
 * @param type {string} The event type
 * @param description {string} Description
 */
export function log(type:string, description:string = ''):void {
    if(!initialized) {
        return;
    }
    let request:XMLHttpRequest = new XMLHttpRequest();
    request.open("POST", httpInterface + '/log', true);
    request.send(JSON.stringify({
        time: now(), type, description
    }));
}


/**
 * Get the current time. Uses high precision timer.
 * @method jibo.performance#now
 * @returns {number} Milliseconds since epoch.
 */
export function now(){
    return performance.timing.navigationStart + performance.now();
}
